Your code is mostly fine. The “vector is not a template” issue on macOS + SFML usually happens because of namespace collisions. SFML internally pulls in some headers that can interfere when you use using namespace std;.

From a maintainability standpoint, the clean fix is simple: stop importing the whole std namespace and explicitly use std::vector, std::stack, etc. This removes ambiguity for the compiler.

Second, you asked for a better GUI flow:

Current flow

click → hull updates immediately

What you want

click → add all points
press RUN → show Graham Scan step-by-step

So we need three things:

Point collection mode

Run key (R)

Step-by-step hull animation

Below is a cleaner version that fixes the vector issue and adds the workflow you want.

Improved Graham Scan Visualizer (C++ + SFML 3)
C++
#include <SFML/Graphics.hpp>
#include <vector>
#include <algorithm>
#include <stack>
#include <thread>
#include <chrono>

struct Point{
    float x,y;
};

std::vector<Point> points;
std::vector<Point> hullSteps;

Point p0;

float distSq(Point p1,Point p2){
    return (p1.x-p2.x)*(p1.x-p2.x)+(p1.y-p2.y)*(p1.y-p2.y);
}

int orientation(Point p,Point q,Point r){
    float val=(q.y-p.y)*(r.x-q.x)-(q.x-p.x)*(r.y-q.y);

    if(val==0) return 0;
    return (val>0)?1:2;
}

bool compare(Point p1,Point p2){
    int o=orientation(p0,p1,p2);

    if(o==0)
        return distSq(p0,p2)>=distSq(p0,p1);

    return (o==2);
}

std::vector<Point> grahamScanStep(std::vector<Point> pts,
                                  sf::RenderWindow &window)
{
    int n=pts.size();
    if(n<3) return {};

    int ymin=0;
    for(int i=1;i<n;i++)
        if((pts[i].y<pts[ymin].y) ||
           (pts[i].y==pts[ymin].y && pts[i].x<pts[ymin].x))
           ymin=i;

    std::swap(pts[0],pts[ymin]);
    p0=pts[0];

    std::sort(pts.begin()+1,pts.end(),compare);

    std::stack<Point> S;

    S.push(pts[0]);
    S.push(pts[1]);
    S.push(pts[2]);

    for(int i=3;i<n;i++)
    {
        while(S.size()>1)
        {
            Point top=S.top();
            S.pop();
            Point next=S.top();
            S.push(top);

            if(orientation(next,top,pts[i])!=2)
                S.pop();
            else
                break;
        }

        S.push(pts[i]);

        // capture step
        std::stack<Point> temp=S;
        std::vector<Point> step;

        while(!temp.empty()){
            step.push_back(temp.top());
            temp.pop();
        }

        std::reverse(step.begin(),step.end());
        hullSteps=step;

        window.clear();

        for(auto &p:points){
            sf::CircleShape c(4);
            c.setPosition({p.x,p.y});
            c.setFillColor(sf::Color::White);
            window.draw(c);
        }

        for(int j=0;j<hullSteps.size()-1;j++){
            sf::Vertex line[2];
            line[0].position={hullSteps[j].x,hullSteps[j].y};
            line[1].position={hullSteps[j+1].x,hullSteps[j+1].y};
            line[0].color=line[1].color=sf::Color::Green;

            window.draw(line,2,sf::PrimitiveType::Lines);
        }

        window.display();

        std::this_thread::sleep_for(std::chrono::milliseconds(600));
    }

    std::vector<Point> hull;

    while(!S.empty()){
        hull.push_back(S.top());
        S.pop();
    }

    std::reverse(hull.begin(),hull.end());
    return hull;
}

int main()
{
    sf::RenderWindow window(
        sf::VideoMode({900,700}),
        "Graham Scan Visualizer");

    std::vector<Point> hull;

    bool run=false;

    while(window.isOpen())
    {
        while(auto event=window.pollEvent())
        {
            if(event->is<sf::Event::Closed>())
                window.close();

            if(event->is<sf::Event::MouseButtonPressed>())
            {
                auto mouse=event->getIf<sf::Event::MouseButtonPressed>();

                if(mouse->button==sf::Mouse::Button::Left && !run)
                {
                    Point p;
                    p.x=mouse->position.x;
                    p.y=mouse->position.y;
                    points.push_back(p);
                }
            }

            if(event->is<sf::Event::KeyPressed>())
            {
                auto key=event->getIf<sf::Event::KeyPressed>();

                if(key->code==sf::Keyboard::Key::R)
                {
                    run=true;
                    hull=grahamScanStep(points,window);
                }
            }
        }

        window.clear();

        for(auto &p:points){
            sf::CircleShape c(4);
            c.setPosition({p.x,p.y});
            c.setFillColor(sf::Color::White);
            window.draw(c);
        }

        if(run && hull.size()>1)
        {
            for(int i=0;i<hull.size();i++)
            {
                sf::Vertex line[2];

                line[0].position={hull[i].x,hull[i].y};
                line[1].position={
                    hull[(i+1)%hull.size()].x,
                    hull[(i+1)%hull.size()].y};

                line[0].color=line[1].color=sf::Color::Red;

                window.draw(line,2,sf::PrimitiveType::Lines);
            }
        }

        window.display();
    }
}
